// Node Code (n8n)
// Soporta items[0].json.message como: array | string | object
// También soporta string con múltiples JSON (uno por línea)

const input = items[0].json;
let raw = input.message;

// 1) Normalizar raw -> array de "entradas" (strings u objetos)
let entries = [];

if (Array.isArray(raw)) {
  entries = raw;
} else if (raw && typeof raw === "string") {
  const s = raw.trim();

  // Si es un JSON único tipo {"a":1}
  if (s.startsWith("{") && s.endsWith("}")) {
    entries = [s];
  } else {
    // Si son varios JSON separados por saltos de línea
    entries = s
      .split("\n")
      .map(x => x.trim())
      .filter(Boolean);
  }
} else if (raw && typeof raw === "object") {
  entries = [raw];
} else {
  entries = [];
}

if (!entries.length) {
  return [
    {
      json: {
        datetime_unix_ms: [],
        datetime_iso: [],
        datetime_readable: [],
        messages: [],
        debug: { reason: "No hay mensajes en input.message", inputType: typeof raw },
      },
    },
  ];
}

// 2) Parsear cada entrada y extraer timestamp
const timesMs = [];
const timesIso = [];
const timesReadable = [];
const payloads = [];

for (const entry of entries) {
  let parsed = null;

  if (typeof entry === "string") {
    const clean = entry.trim();
    try {
      parsed = JSON.parse(clean);
    } catch {
      // si no parsea, lo ignoramos
      continue;
    }
  } else if (entry && typeof entry === "object") {
    parsed = entry;
  } else {
    continue;
  }

  // Timestamp: soporta varios nombres posibles
  const unixSeconds =
    Number(parsed.datetime ?? parsed.timestamp ?? parsed.datatime ?? parsed.time);

  if (!unixSeconds || !Number.isFinite(unixSeconds)) continue;

  const unixMs = unixSeconds * 1000;
  const dateObj = new Date(unixMs);

  timesMs.push(unixMs);
  timesIso.push(dateObj.toISOString());
  timesReadable.push(dateObj.toLocaleString("es-UY"));

  payloads.push({
    message: parsed.message ?? parsed.text ?? parsed.body ?? null,
    sessionid: parsed.sessionid ?? parsed.session_id ?? input.sessionid ?? null,
    datetime_unix_ms: unixMs,
    raw: parsed,
  });
}

return [
  {
    json: {
      datetime_unix_ms: timesMs, // array usable con .last()
      datetime_iso: timesIso,
      datetime_readable: timesReadable,
      messages: payloads,
      debug: {
        inputMessageType: Array.isArray(raw) ? "array" : typeof raw,
        entriesCount: entries.length,
        parsedCount: payloads.length,
      },
    },
  },
];

