  const j = it.json ?? {};

  // Caso principal: viene como { messages: [{message, sessionid, datetime_unix_ms}, ...] }
  if (Array.isArray(j.messages)) {
    for (const m of j.messages) {
      const msg = (m?.message ?? "").toString().trim();
      if (!msg) continue;

      all.push({
        message: msg,
        sessionid: (m?.sessionid ?? j.sessionid ?? "").toString(),
        datetime_unix_ms: Number(m?.datetime_unix_ms ?? NaN),
      });
    }
    continue;
  }

  // Fallback: viene como array de strings JSON en j.message (tu formato viejo)
  const raw = Array.isArray(j.message) ? j.message : (j.message ? [j.message] : []);
  for (const s of raw) {
    try {
      const obj = typeof s === "string" ? JSON.parse(s) : s;
      const msg = (obj?.message ?? "").toString().trim();
      if (!msg) continue;

      all.push({
        message: msg,
        sessionid: (obj?.sessionid ?? j.sessionid ?? "").toString(),
        datetime_unix_ms: Number(obj?.datetime_unix_ms ?? NaN),
      });
    } catch {
      const msg = (s ?? "").toString().trim();
      if (!msg) continue;

      all.push({ message: msg, sessionid: (j.sessionid ?? "").toString(), datetime_unix_ms: NaN });
