const items = $input.all();
const result = [];

items.forEach(item => {
  const output = item.json?.output || item.json || {};

  // Nuevo formato: array de mensajes
  if (output.messages && Array.isArray(output.messages)) {
    output.messages.forEach(message => {
      result.push({
        json: {
          message: message
        }
      });
    });
  }
  // Fallback: formato viejo por si acaso
  else {
    let i = 1;
    while (output[`message${i}`]) {
      result.push({
        json: {
          message: output[`message${i}`]
        }
      });
      i++;
    }
  }
});

return result;

const inputData = $input.all();
let factsText = '';

for (const item of inputData) {
  try {
    const parsedData = JSON.parse(item.json.data);
    const facts = parsedData.edges.map(edge => edge.fact);
    const formattedFacts = facts
      .map((fact, index) => `Fact${index + 1}: ${fact}`)
      .join('\n');
    factsText += formattedFacts + '\n\n';
  } catch (error) {
    console.error('Error procesando facts:', error);
    continue;
  }
}

return [
  {
    json: {
      factsText: factsText.trim() || 'Sin hechos relevantes'
    }
  }
];

